// ProjectCard.js
import React from 'react';
import {
  Card,
  CardContent,
  CardMedia,
  Typography,
  Box,
  Chip,
  Stack,
  CardActionArea
} from '@mui/material';
import { GitHub, Launch } from '@mui/icons-material';

const ProjectCard = ({ project }) => {
  const { title, description, image, techStack, demoLink, githubLink, emoji } = project;
  
  return (
    <Card
      sx={{
        height: 500, // Fixed height for all cards
        display: 'flex',
        flexDirection: 'column',
        backgroundColor: 'background.paper',
        border: '1px solid',
        borderColor: 'divider',
        borderRadius: 2,
        transition: 'transform 0.3s ease-in-out, box-shadow 0.3s ease-in-out',
        '&:hover': {
          transform: 'translateY(-8px)',
          boxShadow: '0 10px 20px rgba(0,0,0,0.2)'
        }
      }}
    >
      <CardMedia
        component="img"
        height="200" // Fixed height for image
        image={image || `/assets/projects/placeholder.png`}
        alt={title}
        sx={{ 
          objectFit: 'cover',
          backgroundSize: 'cover',
          backgroundPosition: 'center'
        }}
      />
      <CardContent 
        sx={{ 
          p: 3,
          display: 'flex',
          flexDirection: 'column',
          height: 300, // Fixed height for content area
          overflow: 'hidden'
        }}
      >
        {/* Title Section - Fixed height */}
        <Box sx={{ height: 40, mb: 1 }}>
          <Typography variant="h5" component="div" sx={{ display: 'flex', alignItems: 'center' }}>
            {emoji && <Box component="span" mr={1} fontSize="1.5rem">{emoji}</Box>}
            {title}
          </Typography>
        </Box>
        
        {/* Description Section - Fixed height */}
        <Box sx={{ height: 80, mb: 2, overflow: 'hidden' }}>
          <Typography 
            variant="body2" 
            color="text.secondary" 
            sx={{ 
              overflow: 'hidden',
              display: '-webkit-box',
              WebkitLineClamp: 4,
              WebkitBoxOrient: 'vertical',
              textOverflow: 'ellipsis'
            }}
          >
            {description}
          </Typography>
        </Box>
        
        {/* Tech Stack Section - Fixed height */}
        <Box sx={{ height: 100, mb: 2 }}>
          <Typography variant="subtitle2" color="primary" gutterBottom>
            Tech Stack:
          </Typography>
          <Stack 
            direction="row" 
            spacing={1} 
            flexWrap="wrap"
          >
            {techStack.map((tech, index) => (
              <Chip
                key={index}
                label={tech}
                size="small"
                sx={{
                  mr: 0.5,
                  mb: 0.5,
                  backgroundColor: 'primary.dark',
                  color: 'primary.contrastText'
                }}
              />
            ))}
          </Stack>
        </Box>
        
        {/* Links Section - Fixed at bottom */}
        <Box sx={{ 
          mt: 'auto', 
          pt: 2,
          display: 'flex', 
          gap: 2 
        }}>
          {githubLink && (
            <Box
              component="a"
              href={githubLink}
              target="_blank"
              rel="noopener noreferrer"
              sx={{
                display: 'flex',
                alignItems: 'center',
                color: 'text.secondary',
                textDecoration: 'none',
                '&:hover': { color: 'primary.main' }
              }}
            >
              <GitHub sx={{ mr: 0.5 }} fontSize="small" />
              <Typography variant="button">Code</Typography>
            </Box>
          )}
          {demoLink && (
            <Box
              component="a"
              href={demoLink}
              target="_blank"
              rel="noopener noreferrer"
              sx={{
                display: 'flex',
                alignItems: 'center',
                color: 'text.secondary',
                textDecoration: 'none',
                '&:hover': { color: 'primary.main' }
              }}
            >
              <Launch sx={{ mr: 0.5 }} fontSize="small" />
              <Typography variant="button">Live Demo</Typography>
            </Box>
          )}
        </Box>
      </CardContent>
    </Card>
  );
};

export default ProjectCard;
